path=Path('/tmp/myDataLeak-Revenge/challenge/raw_sys_b.csv')
rows=[]
for i,line in enumerate(path.read_bytes().splitlines()[1:], start=0):
    parts=line.split(b',')
    if len(parts)!=4: continue
    nameb=parts[1]
    try: g=nameb.decode('gbk'); u=nameb.decode('utf-8')
    except: continue
    if g!=u:
        if len(nameb) in (4,6):
            p,s=nameb[:2],nameb[2:]
            rows.append((i,p,s,g,u))
# stable token maps by raw bytes ascending
prefixes=sorted({p for _,p,_,_,_ in rows})
suffixes=sorted({s for _,_,s,_,_ in rows})
pmap={p:i for i,p in enumerate(prefixes)}
smap={s:i for i,s in enumerate(suffixes)}
digits=[pmap[p]*len(suffixes)+smap[s] for _,p,s,_,_ in rows]
print('base',len(prefixes)*len(suffixes),'prefix',len(prefixes),'suffix',len(suffixes),'rows',len(rows))
print('digits first 80',digits[:80])
# brute pack base28 digits in groups 2..6 into bytes modulo 256 / exact bitpacking
flagre=re.compile(rb'flag\{[^\}]{0,120}\}',re.I)
base=len(prefixes)*len(suffixes)
for grp in range(2,7):
    out=[]
    for i in range(0,len(digits)-grp+1,grp):
        v=0
        for d in digits[i:i+grp]: v=v*base+d
        out.append(v)
        out.append(v%256)
    data=bytes(x%256 for x in out)
    m=flagre.search(data)
